// Generated by GitHub Copilot
(() => {
  const ccGameDurationMs = 10000;

  const ccGameDialog = document.getElementById("cc-game-dialog");
  const ccGameOpenBtn = document.getElementById("cc-game-open");
  const ccGameCloseBtn = document.getElementById("cc-game-close");

  const ccGameStartBtn = document.getElementById("cc-game-start-btn");
  const ccGameRestartBtn = document.getElementById("cc-game-restart-btn");
  const ccGameClickArea = document.getElementById("cc-game-click-area");
  const ccGameTimeLeft = document.getElementById("cc-game-time-left");
  const ccGameClickCount = document.getElementById("cc-game-click-count");
  const ccGameCps = document.getElementById("cc-game-cps");
  const ccGameFinalResult = document.getElementById("cc-game-final-result");

  let ccGameClicks = 0;
  let ccGameStartedAt = null;
  let ccGameEndsAt = null;
  let ccGameTimerId = null;
  let ccGameRunning = false;

  if (
    !ccGameDialog ||
    !ccGameOpenBtn ||
    !ccGameCloseBtn ||
    !ccGameStartBtn ||
    !ccGameRestartBtn ||
    !ccGameClickArea ||
    !ccGameTimeLeft ||
    !ccGameClickCount ||
    !ccGameCps ||
    !ccGameFinalResult
  ) {
    return;
  }

  /**
   * Opens game dialog and updates accessibility state.
   */
  function ccGameOpenDialog() {
    if (typeof ccGameDialog.showModal === "function") {
      ccGameDialog.showModal();
    } else {
      ccGameDialog.setAttribute("open", "");
    }
    ccGameOpenBtn.setAttribute("aria-expanded", "true");
    ccGameStartBtn.focus();
  }

  /**
   * Closes game dialog and updates accessibility state.
   */
  function ccGameCloseDialog() {
    if (ccGameDialog.hasAttribute("open")) {
      ccGameDialog.close?.();
      ccGameDialog.removeAttribute("open");
    }
    ccGameOpenBtn.setAttribute("aria-expanded", "false");
  }

  /**
   * Render the baseline UI values when game is not running.
   */
  function ccGameResetUi() {
    ccGameClicks = 0;
    ccGameStartedAt = null;
    ccGameEndsAt = null;
    ccGameRunning = false;

    ccGameTimeLeft.textContent = "10.0s";
    ccGameClickCount.textContent = "0";
    ccGameCps.textContent = "0.00";
    ccGameClickArea.textContent = "Press Start to Play";
    ccGameFinalResult.textContent = "Press Start to begin the 10-second challenge.";

    ccGameClickArea.disabled = true;
    ccGameClickArea.setAttribute("aria-disabled", "true");
    ccGameClickArea.classList.add("cc-game-click-area-disabled");

    ccGameStartBtn.disabled = false;
    ccGameRestartBtn.disabled = true;
  }

  /**
   * Enable clicking only while the active game window is open.
   */
  function ccGameEnableClickArea() {
    ccGameClickArea.disabled = false;
    ccGameClickArea.setAttribute("aria-disabled", "false");
    ccGameClickArea.classList.remove("cc-game-click-area-disabled");
    ccGameClickArea.textContent = "Click Here Fast!";
  }

  /**
   * Disable clicking when game is idle or finished.
   */
  function ccGameDisableClickArea() {
    ccGameClickArea.disabled = true;
    ccGameClickArea.setAttribute("aria-disabled", "true");
    ccGameClickArea.classList.add("cc-game-click-area-disabled");
  }

  /**
   * Update countdown and live CPS metrics.
   */
  function ccGameTick() {
    if (!ccGameRunning || !ccGameStartedAt || !ccGameEndsAt) {
      return;
    }

    const ccGameNow = Date.now();
    const ccGameMsLeft = Math.max(0, ccGameEndsAt - ccGameNow);
    const ccGameElapsedSec = Math.max(0.001, (ccGameNow - ccGameStartedAt) / 1000);

    ccGameTimeLeft.textContent = `${(ccGameMsLeft / 1000).toFixed(1)}s`;
    ccGameCps.textContent = (ccGameClicks / ccGameElapsedSec).toFixed(2);

    if (ccGameMsLeft <= 0) {
      ccGameEnd();
    }
  }

  /**
   * Start a new 10-second round and arm event updates.
   */
  function ccGameStart() {
    if (ccGameRunning) {
      return;
    }

    ccGameClicks = 0;
    ccGameRunning = true;
    ccGameStartedAt = Date.now();
    ccGameEndsAt = ccGameStartedAt + ccGameDurationMs;

    ccGameClickCount.textContent = "0";
    ccGameCps.textContent = "0.00";
    ccGameFinalResult.textContent = "Game running: keep clicking until time reaches 0.0s.";

    ccGameStartBtn.disabled = true;
    ccGameRestartBtn.disabled = false;

    ccGameEnableClickArea();
    ccGameTick();

    if (ccGameTimerId) {
      clearInterval(ccGameTimerId);
    }
    ccGameTimerId = setInterval(ccGameTick, 50);
  }

  /**
   * End the current round and freeze final metrics.
   */
  function ccGameEnd() {
    if (!ccGameRunning) {
      return;
    }

    ccGameRunning = false;

    if (ccGameTimerId) {
      clearInterval(ccGameTimerId);
      ccGameTimerId = null;
    }

    const ccGameElapsedSec = ccGameDurationMs / 1000;
    const ccGameFinalCps = (ccGameClicks / ccGameElapsedSec).toFixed(2);

    ccGameTimeLeft.textContent = "0.0s";
    ccGameCps.textContent = ccGameFinalCps;
    ccGameClickArea.textContent = "Time Up!";
    ccGameDisableClickArea();

    ccGameFinalResult.textContent = `Final result: ${ccGameClicks} clicks in 10s (${ccGameFinalCps} CPS).`;

    ccGameRestartBtn.disabled = false;
    ccGameStartBtn.disabled = true;
  }

  /**
   * Count a click only during active gameplay.
   */
  function ccGameHandleClick() {
    if (!ccGameRunning) {
      return;
    }

    ccGameClicks += 1;
    ccGameClickCount.textContent = String(ccGameClicks);
  }

  /**
   * Reset state so user can start another round.
   */
  function ccGameRestart() {
    if (ccGameTimerId) {
      clearInterval(ccGameTimerId);
      ccGameTimerId = null;
    }
    ccGameResetUi();
  }

  ccGameOpenBtn.addEventListener("click", ccGameOpenDialog);
  ccGameCloseBtn.addEventListener("click", ccGameCloseDialog);

  ccGameDialog.addEventListener("click", (event) => {
    const dialogBox = ccGameDialog.getBoundingClientRect();
    const clickedOutside =
      event.clientX < dialogBox.left ||
      event.clientX > dialogBox.right ||
      event.clientY < dialogBox.top ||
      event.clientY > dialogBox.bottom;

    if (clickedOutside) {
      ccGameCloseDialog();
    }
  });

  ccGameDialog.addEventListener("cancel", (event) => {
    event.preventDefault();
    ccGameCloseDialog();
  });

  ccGameDialog.addEventListener("close", () => {
    ccGameOpenBtn.setAttribute("aria-expanded", "false");
  });

  ccGameStartBtn.addEventListener("click", ccGameStart);
  ccGameRestartBtn.addEventListener("click", ccGameRestart);
  ccGameClickArea.addEventListener("click", ccGameHandleClick);

  ccGameOpenBtn.setAttribute("aria-expanded", "false");
  ccGameResetUi();
})();